#include <stdio.h>

int main() {
    int k, n, w;
    scanf("%d %d %d", &k, &n, &w);
    int s = ((2 * k + k * (w - 1)) * w) / 2;
    if (s > n) {
        printf("%d\n", s - n);
    } else {
        printf("0\n");
    }
    return 0;
}
